    64→          </div>
    65→        )}
    66→
    67→        {isStreaming && !pendingText && (
    68→          <ThinkingIndicator />
    69→        )}
    70→
    71→        <div ref={bottomRef} />
    72→      </div>
    73→
    74→      {/* Streaming status bar */}
    75→      {isStreaming && pendingText && (
    76→        <div className="flex items-center gap-2 border-t border-border-subtle px-4 py-1.5 text-[11px] text-fg-subtle">
    77→          <span className="relative flex h-2 w-2">
    78→            <span className="absolute inline-flex h-full w-full animate-ping rounded-full bg-accent opacity-75" />
    79→            <span className="relative inline-flex h-2 w-2 rounded-full bg-accent" />
    80→          </span>
    81→          <span>Planning agent is responding...</span>
    82→        </div>
    83→      )}
    84→
    85→      {/* Input */}
    86→      <div className="border-t border-border-subtle px-3 py-2">
    87→        <div className="flex gap-2">
    88→          <input
    89→            type="text"
    90→            value={input}
    91→            onChange={(e) => setInput(e.target.value)}
    92→            onKeyDown={(e) => e.key === "Enter" && handleSend()}
    93→            placeholder={isStreaming ? "Waiting for response..." : "Describe your feature or answer questions..."}
    94→            disabled={isStreaming}
    95→            className="flex-1 rounded border border-border bg-bg px-2.5 py-1.5 text-xs text-fg placeholder:text-fg-faint focus:border-accent focus:outline-none disabled:opacity-50"
    96→          />
    97→          <button
